import React, { useState, useEffect, useRef, useCallback } from 'react';
import './App.css';

const API = 'http://localhost:3001';

export default function App() {
  const [token, setToken] = useState(localStorage.getItem('youtube_token') || null);

  useEffect(() => {
    // 1. Check if returning from Google OAuth
    const urlParams = new URLSearchParams(window.location.search);
    const urlToken = urlParams.get('token');

    if (urlToken) {
      setToken(urlToken);
      localStorage.setItem('youtube_token', urlToken);
      window.history.replaceState({}, document.title, window.location.pathname);
    }
  }, []);

  const handleLogin = () => {
    window.location.href = `${API}/login`;
  };

  const handleLogout = () => {
    setToken(null);
    localStorage.removeItem('youtube_token');
  };

  if (!token) {
    return (
      <>
        <div className="bg-orbs">
          <div className="orb orb-1"></div>
          <div className="orb orb-2"></div>
          <div className="orb orb-3"></div>
        </div>
        <div className="login-screen">
          <div className="login-panel">
            <div className="brand" style={{marginBottom: 24, justifyContent: 'center'}}>
              <div className="brand-dot" />
              <span className="brand-name">Tune<span className="accent">AI</span></span>
            </div>

            <h1 className="hero-title" style={{fontSize: 'clamp(40px, 6vw, 64px)', marginBottom: 16}}>
              Curate your <br/><em>personal taste.</em>
            </h1>

            <p className="hero-tagline" style={{marginBottom: 40}}>
              Connect your YouTube account. Our AI will analyze your actual liked videos and build perfect playlists for any mood.
            </p>

            <button className="spotify-btn" onClick={handleLogin} style={{backgroundColor: '#FF0000', color: '#fff'}}>
              <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor">
                <path d="M21.582,6.186c-0.23-0.86-0.908-1.538-1.768-1.768C18.254,4,12,4,12,4S5.746,4,4.186,4.418 c-0.86,0.23-1.538,0.908-1.768,1.768C2,7.746,2,12,2,12s0,4.254,0.418,5.814c0.23,0.86,0.908,1.538,1.768,1.768 C5.746,20,12,20,12,20s6.254,0,7.814-0.418c0.86-0.23,1.538-0.908,1.768-1.768C22,16.254,22,12,22,12S22,7.746,21.582,6.186z M10,15.464V8.536L16,12L10,15.464z"/>
              </svg>
              Connect with YouTube
            </button>
            <p style={{marginTop: 16, fontSize: 13, color: 'var(--text-muted)'}}>We only fetch your liked songs. We never delete your data.</p>
          </div>
        </div>
      </>
    );
  }

  return <Dashboard token={token} onLogout={handleLogout} />;
}


// ── DASHBOARD COMPONENT ──
function Dashboard({ token, onLogout }) {
  const [query, setQuery]           = useState('');
  const [mood, setMood]             = useState('');
  const [genre, setGenre]           = useState('');
  const [playlist, setPlaylist]     = useState(null);
  const [loading, setLoading]       = useState(false);
  const [error, setError]           = useState('');
  const [playing, setPlaying]       = useState(null);

  // ── SPOTIFY USER DATA ──
  const [userProfile, setUserProfile] = useState(null);
  const [likedSongs, setLikedSongs]   = useState([]);

  const [pinnedIds, setPinnedIds]   = useState([]);
  const [didYouMean, setDidYouMean] = useState(null);
  const [showHistory, setShowHistory] = useState(false);
  const [history, setHistory]       = useState([]);
  const [toast, setToast]           = useState('');
  const searchTimer = useRef(null);
  const toastTimer  = useRef(null);
  const audioRef    = useRef(null);

  const MOODS = ['Energetic','Chill','Happy','Melancholic','Focus','Late Night','Workout','Party'];

  useEffect(() => {
    loadPins();
    if(token) fetchYouTubeData();
  }, [token]);

  async function fetchYouTubeData() {
    try {
      // 1. Fetch User Profile
      const meRes = await fetch('https://www.googleapis.com/oauth2/v1/userinfo?alt=json', { headers: { Authorization: `Bearer ${token}` } });
      if (meRes.status === 401) return onLogout(); // Token expired!
      const meData = await meRes.json();
      setUserProfile({ display_name: meData.name, images: [{ url: meData.picture }] });

      // 2. Fetch User's Liked Videos (Playlist ID: LL)
      const tracksRes = await fetch('https://www.googleapis.com/youtube/v3/playlistItems?part=snippet&playlistId=LL&maxResults=50', { headers: { Authorization: `Bearer ${token}` } });
      const tracksData = await tracksRes.json();
      if (tracksData.items) {
        const formattedTracks = tracksData.items.map(item => ({
          id: item.snippet.resourceId?.videoId,
          title: item.snippet.title,
          artist: item.snippet.videoOwnerChannelTitle || 'Unknown',
          preview: null,
          image: item.snippet.thumbnails?.high?.url || item.snippet.thumbnails?.default?.url
        }));
        setLikedSongs(formattedTracks);
      }
    } catch (err) {
      console.error('Failed to fetch YouTube personal data:', err);
    }
  }

  // ── AUDIO PREVIEW ENGINE ──
  // YouTube doesn't offer raw MP3 previews, so we use an inline iframe player in the track list instead!
  useEffect(() => {
    // Left empty since playing state is handled by the inline iframe markup
  }, [playing, playlist]);

  async function loadPins() {
    try {
      const res  = await fetch(`${API}/pins?userId=AUTH_USER`);
      const data = await res.json();
      setPinnedIds((data || []).map(s => s.id));
    } catch {}
  }

  function showToast(msg) {
    setToast(msg);
    clearTimeout(toastTimer.current);
    toastTimer.current = setTimeout(() => setToast(''), 2500);
  }

  function handleQueryChange(val) {
    setQuery(val);
    clearTimeout(searchTimer.current);
    if (!val.trim()) { setDidYouMean(null); return; }
    searchTimer.current = setTimeout(async () => {
      try {
        const res  = await fetch(`${API}/search?q=${encodeURIComponent(val)}&token=${token}`);
        const data = await res.json();
        if (data.didYouMean) setDidYouMean(data.didYouMean);
        else setDidYouMean(null);
      } catch {}
    }, 500);
  }

  const generate = useCallback(async () => {
    setLoading(true);
    setError('');
    setPlaying(null);
    try {
      const res  = await fetch(`${API}/generate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          userId: "AUTH_USER",
          token: token,
          mood,
          genre,
          artists: query,
          libraryStr: likedSongs.slice(0, 50).map(s => `- "${s.title}" by ${s.artist}`).join('\n')
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Failed to generate');
      setPlaylist(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [mood, genre, query]);

  async function togglePin(song) {
    const isPinned = pinnedIds.includes(song.id || song.title);
    const songId   = song.id || song.title;
    if (isPinned) {
      await fetch(`${API}/pin`, {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: "AUTH_USER", songId }),
      });
      setPinnedIds(prev => prev.filter(id => id !== songId));
      showToast('Removed from saved');
    } else {
      await fetch(`${API}/pin`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          userId: "AUTH_USER",
          song: { id: songId, title: song.title, artist: song.artist },
        }),
      });
      setPinnedIds(prev => [...prev, songId]);
      showToast('❤️ Saved!');
    }
  }

  async function loadHistory() {
    try {
      const res  = await fetch(`${API}/playlists?userId=AUTH_USER`);
      const data = await res.json();
      setHistory(Array.isArray(data) ? data : []);
      setShowHistory(true);
    } catch { setHistory([]); setShowHistory(true); }
  }

  return (
    <>
      <div className="bg-orbs">
        <div className="orb orb-1"></div>
        <div className="orb orb-2"></div>
        <div className="orb orb-3"></div>
      </div>

      <div className="app-layout">

        {/* ── FLOATING NAV PILL ── */}
        <nav className="nav-pill">
          <div className="brand" style={{ gap: '12px' }}>
            {userProfile?.images?.[0] ? (
              <img src={userProfile.images[0].url} alt="Profile" style={{ width: 28, height: 28, borderRadius: '50%' }} />
            ) : (
              <div className="brand-dot" />
            )}
            <span className="brand-name">
              {userProfile ? userProfile.display_name : 'Tune'}
              <span className="accent">AI</span>
            </span>
          </div>
          <div className="nav-actions">
            {likedSongs.length > 0 && (
              <span className="pinned-count">❤️ {likedSongs.length} Liked</span>
            )}
            <button className="btn-history" onClick={loadHistory}>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 6h16M4 12h16M4 18h16"></path></svg>
              History
            </button>
            <button className="btn-history" onClick={onLogout} style={{color: '#ff6b6b'}}>
              Log out
            </button>
          </div>
        </nav>

        <div className="main-content">
          {/* ── HERO TEXT ── */}
          <div className="hero-center">
            <h1 className="hero-title">Your taste,<br/><em>reimagined.</em></h1>
            <p className="hero-tagline">
              Discover and build perfect playlists using AI. Just describe your vibe, a favorite artist, or even lyrics you barely remember.
            </p>
          </div>

          {/* ── BENTO BOX COMMAND CENTER ── */}
          <div className="bento-box">

            {/* Top Row: Omnibar */}
            <div className="bento-omnibar">
              <span className="omni-icon">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
              </span>
              <input
                className="omni-input"
                type="text"
                placeholder="What do you want to listen to?"
                value={query}
                onChange={e => handleQueryChange(e.target.value)}
              />
              {query && (
                <button className="omni-clear" onClick={() => { setQuery(''); setDidYouMean(null); }}>
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                </button>
              )}
            </div>

            {/* Did You Mean (pops down gracefully) */}
            {didYouMean && (
              <div className="dym-banner">
                <span className="dym-text">Did you mean <strong className="dym-highlight">{didYouMean}</strong>?</span>
                <button className="dym-btn" onClick={() => { setQuery(didYouMean); setDidYouMean(null); }}>Use this</button>
              </div>
            )}

            <div className="bento-split">
              {/* Left Column: Moods */}
              <div className="bento-panel mood-panel">
                <div className="panel-label">Set the Mood</div>
                <div className="mood-grid">
                  {MOODS.map(m => (
                    <button
                      key={m}
                      className={`bento-chip${mood === m.toLowerCase() ? ' active' : ''}`}
                      onClick={() => setMood(mood === m.toLowerCase() ? '' : m.toLowerCase())}
                    >
                      {m}
                    </button>
                  ))}
                </div>
              </div>

              {/* Right Column: Genre */}
              <div className="bento-panel genre-panel">
                <div className="panel-label">Refine Genre</div>
                <div className="select-wrapper">
                  <select className="bento-select" value={genre} onChange={e => setGenre(e.target.value)}>
                    <option value="">Any genre</option>
                    <option value="indie">Indie / Alt</option>
                    <option value="hip-hop">Hip-Hop</option>
                    <option value="electronic">Electronic</option>
                    <option value="r&b">R&B / Soul</option>
                    <option value="pop">Pop</option>
                    <option value="jazz">Jazz</option>
                    <option value="rock">Rock</option>
                    <option value="bollywood">Bollywood</option>
                    <option value="classical">Classical</option>
                  </select>
                  <span className="chevron">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="6 9 12 15 18 9"></polyline></svg>
                  </span>
                </div>
              </div>
            </div>

            <button className={`bento-generate${loading ? ' is-loading' : ''}`} onClick={generate} disabled={loading}>
              {loading ? (
                <div className="loading-state">
                  <div className="spinner"></div> Curating...
                </div>
              ) : (
                <span className="gen-text">✨ Generate My Playlist</span>
              )}
            </button>
          </div>

          {error && <div className="bento-error">⚠️ {error}</div>}

          {/* ── PLAYLIST RESULTS ── */}
          {playlist && (
            <div className="player-card">
              <div className="player-header">
                <div className="player-art">
                  <svg width="32" height="32" viewBox="0 0 24 24" fill="#fff"><path d="M12 3v10.55A4 4 0 1014 17V7h4V3h-6z"/></svg>
                </div>
                <div className="player-meta">
                  <h2>{playlist.title}</h2>
                  <p>{playlist.description}</p>
                </div>
                <div className="player-actions">
                  <button className="p-btn p-btn-primary" onClick={generate}>Regenerate</button>
                  <button className="p-btn p-btn-secondary" onClick={() => setPlaylist(null)}>Clear</button>
                </div>
              </div>

              <div className="track-list">
                {(playlist.songs || []).map((song, i) => {
                  const songId = song.id || song.title;
                  const isPinned = pinnedIds.includes(songId);
                  return (
                    <div key={i} className={`track-item${playing === i ? ' is-playing' : ''}`} onClick={() => setPlaying(playing === i ? null : i)}>
                      <div className="track-num">{playing === i ? <span className="playing-bars"><span/><span/><span/></span> : i + 1}</div>

                      <div className="track-info">
                        <div className="track-title">{song.title}</div>
                        <div className="track-artist">{song.artist}</div>
                        {playing === i && song.id && (
                          <div style={{marginTop: 8}}>
                            <iframe width="100%" height="80" 
                              src={`https://www.youtube.com/embed/${song.id}?autoplay=1`}
                              title="YouTube video player" frameBorder="0" 
                              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                              style={{borderRadius: 8}}>
                            </iframe>
                          </div>
                        )}
                      </div>

                      <div className="track-reason">{song.reason}</div>

                      <button className={`track-pin${isPinned ? ' is-pinned' : ''}`} onClick={e => { e.stopPropagation(); togglePin(song); }}>
                        <svg width="20" height="20" viewBox="0 0 24 24" fill={isPinned ? '#e91e8c' : 'none'} stroke={isPinned ? '#e91e8c' : 'currentColor'} strokeWidth="2">
                          <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path>
                        </svg>
                      </button>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* ── HISTORY MODAL ── */}
      {showHistory && (
        <div className="modal-backdrop" onClick={() => setShowHistory(false)}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>Playlists</h3>
              <button className="modal-close" onClick={() => setShowHistory(false)}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
              </button>
            </div>
            {history.length === 0 ? (
              <div className="modal-empty-state">No playlists beautifully crafted yet.</div>
            ) : (
              <div className="history-list">
                {history.map((pl, i) => (
                  <div key={i} className="hist-row" onClick={() => { setPlaylist(pl); setShowHistory(false); }}>
                    <div className="hist-icon">🎵</div>
                    <div className="hist-meta">
                      <div className="hist-title">{pl.title}</div>
                      <div className="hist-date">{pl.songs?.length || 0} tracks • {new Date(pl.createdAt).toLocaleDateString()}</div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      {/* ── TOAST ── */}
      {toast && <div className="toast-notification">{toast}</div>}
    </>
  );
}
